## Claude Desktop config

Add to `~/Library/Application Support/Claude/claude_desktop_config.json`:

```json
{
  "mcpServers": {
    "open-meteo": {
      "command": "node",
      "args": ["/absolute/path/to/open-meteo-mcp/dist/index.js"]
    }
  }
}
```

Restart Claude Desktop. Example prompts:

- *"What's the weather in Moscow this week?"* → `geocode` → `get_forecast`
- *"Collect temperature in Saint Petersburg every hour"* → `schedule_weather_job`
- *"Show me the air quality summary for the last 24h"* → `get_weather_summary`

export async function openMeteoFetch(
  baseUrl: string,
  params: Record<string, unknown>
): Promise<unknown> {
  const query = new URLSearchParams();

  for (const [key, value] of Object.entries(params)) {
    if (value === undefined || value === null) continue;
    if (Array.isArray(value)) {
      // Open-Meteo expects repeated keys for arrays: hourly=temperature_2m&hourly=windspeed_10m
      for (const item of value) {
        query.append(key, String(item));
      }
    } else {
      query.set(key, String(value));
    }
  }

  const url = `${baseUrl}?${query.toString()}`;
  const res = await fetch(url);

  if (!res.ok) {
    const body = await res.text();
    throw new Error(`Open-Meteo API error ${res.status}: ${body}`);
  }

  return res.json();
}

import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { StreamableHTTPServerTransport } from "@modelcontextprotocol/sdk/server/streamableHttp.js";
import { createServer, type IncomingMessage, type ServerResponse } from "http";
import { randomUUID } from "crypto";
import {
  registerForecast,
  registerArchive,
  registerAirQuality,
  registerMarine,
  registerElevation,
  registerGeocoding,
  registerFlood,
  registerEnsemble,
  registerClimate,
  registerSeasonal,
  registerDwdIcon,
  registerEcmwf,
  registerScheduleTools,
  registerAnalyzeTools,
} from "./tools/index.js";
import { restoreJobs } from "./scheduler.js";
import { registerSession, unregisterSession } from "./notifications.js";

function createMcpServer() {
  // `logging` capability lets the server push summaries via logging notifications.
  const server = new McpServer(
    { name: "open-meteo", version: "2.2.1" },
    { capabilities: { logging: {} } }
  );
  registerForecast(server);
  registerArchive(server);
  registerAirQuality(server);
  registerMarine(server);
  registerElevation(server);
  registerGeocoding(server);
  registerFlood(server);
  registerEnsemble(server);
  registerClimate(server);
  registerSeasonal(server);
  registerDwdIcon(server);
  registerEcmwf(server);
  registerScheduleTools(server);
  registerAnalyzeTools(server);
  return server;
}

restoreJobs();

const transport = process.env.MCP_TRANSPORT ?? "stdio";

if (transport === "http") {
  const port = parseInt(process.env.PORT ?? "3000", 10);

  // Stateful sessions: keep one transport (and its server) alive per session so
  // the server can push notifications over the session's SSE stream.
  const transports: Record<string, StreamableHTTPServerTransport> = {};

  const httpServer = createServer(async (req: IncomingMessage, res: ServerResponse) => {
    res.setHeader("Access-Control-Allow-Origin", "*");
    res.setHeader("Access-Control-Allow-Methods", "GET, POST, DELETE, OPTIONS");
    res.setHeader("Access-Control-Allow-Headers", "Content-Type, Accept, Mcp-Session-Id, Last-Event-ID");
    res.setHeader("Access-Control-Expose-Headers", "Mcp-Session-Id");

    if (req.method === "OPTIONS") {
      res.writeHead(204);
      res.end();
      return;
    }

    if (req.url !== "/mcp") {
      res.writeHead(404);
      res.end("Not found");
      return;
    }

    const sessionId = req.headers["mcp-session-id"] as string | undefined;

    // Existing session: route to its live transport (POST / GET-SSE / DELETE).
    if (sessionId && transports[sessionId]) {
      await transports[sessionId].handleRequest(req, res);
      return;
    }

    // New session: only a POST (initialize handshake) may create one.
    if (req.method !== "POST") {
      res.writeHead(400);
      res.end("Missing or unknown Mcp-Session-Id");
      return;
    }

    const server = createMcpServer();
    const mcpTransport = new StreamableHTTPServerTransport({
      sessionIdGenerator: () => randomUUID(),
      onsessioninitialized: (sid: string) => {
        transports[sid] = mcpTransport;
        registerSession(sid, server);
      },
    });
    mcpTransport.onclose = () => {
      const sid =

string) => {
        transports[sid] = mcpTransport;
        registerSession(sid, server);
      },
    });
    mcpTransport.onclose = () => {
      const sid = mcpTransport.sessionId;
      if (sid) {
        delete transports[sid];
        unregisterSession(sid);
      }
    };

    await server.connect(mcpTransport);
    await mcpTransport.handleRequest(req, res);
  });

  httpServer.listen(port, "0.0.0.0", () => {
    console.error(`open-meteo MCP HTTP (stateful) listening on http://0.0.0.0:${port}/mcp`);
  });
} else {
  const server = createMcpServer();
  const stdioTransport = new StdioServerTransport();
  await server.connect(stdioTransport);
}

import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { summarize } from "./summarize.js";

// Live transport sessions: sessionId -> the McpServer bound to that connection.

const servers = new Map<string, McpServer>();
// Subscriptions: transport sessionId -> set of app session_ids (job owners)
// it wants summary pushes for, with the period to aggregate.
interface Sub {
  appSession: string;
  period: string;
}

export function registerSession(sessionId: string, server: McpServer) {
  servers.set(sessionId, server);
}

export function unregisterSession(sessionId: string) {
  servers.delete(sessionId);
  subs.delete(sessionId);
}

export function subscribe(sessionId: string, appSession: string, period: string) {
  const list = subs.get(sessionId) ?? [];
  if (!list.some((s) => s.appSession === appSession)) {
    list.push({ appSession, period });
  } else {
    for (const s of list) if (s.appSession === appSession) s.period = period;
  }
  subs.set(sessionId, list);
}

export function unsubscribe(sessionId: string, appSession: string): boolean {
  const list = subs.get(sessionId);
  if (!list) return false;
  const next = list.filter((s) => s.appSession !== appSession);
  subs.set(sessionId, next);
  return next.length !== list.length;
}

/** True if any live session is subscribed to this app session. */

export function hasSubscribers(appSession: string): boolean {
  for (const list of subs.values()) {
    if (list.some((s) => s.appSession === appSession)) return true;
  }
  return false;
}

/**
 * Push a fresh summary for `job` to every session subscribed to its owner.
 * Uses an MCP logging notification — the channel standard clients already
 * receive — carrying a structured `weather_summary` payload. Called by the
 * scheduler after each collection, so clients get periodic summaries WITHOUT
 * polling.
 */
export async function pushSummaryForJob(jobId: string, ownerSession: string) {
  // Find subscribers for this owner across all live sessions.
  for (const [sessionId, list] of subs) {
    const sub = list.find((s) => s.appSession === ownerSession);
    if (!sub) continue;
    const server = servers.get(sessionId);
    if (!server) continue;

    const summary = summarize(jobId, sub.period);
    if (!summary || summary.readings_count === 0) continue;

    try {
      await server.server.sendLoggingMessage(
        {
          level: "info",
          logger: "weather_summary",
          data: summary as unknown as Record<string, unknown>,
        },
        sessionId
      );
    } catch {
      /* client gone; cleanup happens on session close */
    }
  }
}

import * as cron from "node-cron";
import { jobsRepo, readingsRepo, type Job } from "./db.js";
import { openMeteoFetch } from "./client.js";
import { pushSummaryForJob } from "./notifications.js";

// active cron tasks, keyed by job id

const activeTasks = new Map<string, cron.ScheduledTask>();

async function runJob(job: Job) {
  try {
    const data = await openMeteoFetch("https://api.open-meteo.com/v1/forecast", {
      latitude: job.latitude,
      longitude: job.longitude,
      hourly: job.variables,
      timezone: "auto",
      forecast_days: 1,
    });
    readingsRepo.insert(job.id, data as Record<string, unknown>);
  } catch (err) {
    readingsRepo.insert(job.id, { error: String(err), fetched_at: Date.now() });
  }
  // Push a fresh summary to any subscribed client (no-op if none). This is what
  // makes periodic delivery server-driven: clients receive without polling.
  await pushSummaryForJob(job.id, job.session_id);
}

export function startJob(job: Job) {
  if (activeTasks.has(job.id)) return;
  const task = cron.schedule(job.cron_expr, () => runJob(job));
  activeTasks.set(job.id, task);
}

export function stopJob(id: string) {
  const task = activeTasks.get(id);
  if (task) {
    task.stop();
    activeTasks.delete(id);
  }
}

export function isRunning(id: string): boolean {
  return activeTasks.has(id);
}

// Restore all persisted jobs on server start (all sessions)

export function restoreJobs() {
  for (const job of jobsRepo.listAll()) {
    startJob(job);
  }
}

import { jobsRepo, readingsRepo } from "./db.js";

export const PERIOD_MS: Record<string, number> = {
  "1h": 1 * 60 * 60 * 1000,
  "6h": 6 * 60 * 60 * 1000,
  "12h": 12 * 60 * 60 * 1000,
  "24h": 24 * 60 * 60 * 1000,
  "7d": 7 * 24 * 60 * 60 * 1000,
  "30d": 30 * 24 * 60 * 60 * 1000,
};

export interface Summary {
  job_id: string;
  location: string;
  session_id: string;
  period: string;
  readings_count: number;
  first_reading?: string;
  last_reading?: string;
  stats: Record<string, { min: number; max: number; avg: number; count: number }>;
}

/**
 * Aggregate a job's recent readings into min/max/avg per variable.
 * Returns null if the job is unknown; `readings_count: 0` if no data yet.
 * Shared by the get_weather_summary tool and the scheduler's push notifications.
 */

export function summarize(job_id: string, period: string): Summary | null {
  const job = jobsRepo.get(job_id);
  if (!job) return null;

  const sinceMs = Date.now() - (PERIOD_MS[period] ?? PERIOD_MS["24h"]);
  const readings = readingsRepo.getRecent(job_id, sinceMs);

  if (readings.length === 0) {
    return {
      job_id,
      location: job.location,
      session_id: job.session_id,
      period,
      readings_count: 0,
      stats: {},
    };
  }

  const buckets: Record<string, number[]> = {};
  for (const reading of readings) {
    const hourly = (reading.data as { hourly?: Record<string, unknown[]> }).hourly;
    if (!hourly) continue;
    for (const [varName, values] of Object.entries(hourly)) {
      if (varName === "time") continue;
      if (!buckets[varName]) buckets[varName] = [];
      for (const v of values) {
        if (typeof v === "number") buckets[varName].push(v);
      }
    }
  }

  const stats: Summary["stats"] = {};
  for (const [varName, values] of Object.entries(buckets)) {
    if (values.length === 0) continue;
    stats[varName] = {
      min: +Math.min(...values).toFixed(2),
      max: +Math.max(...values).toFixed(2),
      avg: +(values.reduce((a, b) => a + b, 0) / values.length).toFixed(2),
      count: values.length,
    };
  }

  return {
    job_id,
    location: job.location,
    session_id: job.session_id,
    period,
    readings_count: readings.length,
    first_reading: new Date(readings[0].fetched_at).toISOString(),
    last_reading: new Date(readings[readings.length - 1].fetched_at).toISOString(),
    stats,
  };
}

import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { z } from "zod";
import { openMeteoFetch } from "../client.js";

export function registerAirQuality(server: McpServer) {
  server.registerTool(
    "get_air_quality",
    {
      description:
        "Get air quality data including PM2.5, PM10, ozone, NO2, SO2, CO, pollen counts, " +
        "and European/US AQI indices. Data from Copernicus CAMS.",
      inputSchema: z.object({
        latitude: z.number().min(-90).max(90),
        longitude: z.number().min(-180).max(180),
        hourly: z.array(AirQualityVar).describe("Air quality variables to retrieve"),
        timezone: z.string().optional().default("auto"),
        forecast_days: z.number().int().min(1).max(7).optional().default(5),
        past_days: z.number().int().min(0).max(92).optional(),
        start_date: z.string().optional().describe("YYYY-MM-DD, overrides forecast_days"),
        end_date: z.string().optional().describe("YYYY-MM-DD"),
      }),
    },
    async (params) => {
      const data = await openMeteoFetch("https://air-quality-api.open-meteo.com/v1/air-quality", params);
      return { content: [{ type: "text", text: JSON.stringify(data, null, 2) }] };
    }
  );
}

import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { z } from "zod";
import {
  ACTIVITIES,
  type Activity,
  type NDay,
  normalizeDaily,
  wmoDescription,
  scoreActivityDay,
  gridPoints,
} from "./weather-logic.js";

// ── shared schemas ─────────────────────────────────────────────────────────
// A normalized day as produced by summarize_forecast. Kept loose (passthrough)
// so the agent can hand days between tools without field-by-field surgery.

const ActivityEnum = z.enum(ACTIVITIES).describe(
  "Outdoor activity to weigh the weather for. Affects ideal temperature band and rain/wind sensitivity."
);

function jsonResult(obj: unknown) {
  return { content: [{ type: "text" as const, text: JSON.stringify(obj, null, 2) }] };
}

function summaryLine(d: NDay): string {
  return `${d.weather ?? wmoDescription(d.weather_code ?? -1)}, ${d.temp_min}–${d.temp_max}°C, ` +
    `rain ${d.precipitation_mm}mm (${d.rain_probability_pct}%), wind ${d.wind_speed_kmh} km/h, ` +
    `${d.sunshine_hours}h sun, UV ${d.uv_index}`;
}

export function registerAnalyzeTools(server: McpServer) {

  // ── summarize_forecast — raw get_forecast JSON → normalized days ──────────
  server.registerTool(
    "summarize_forecast",
    {
      description:
        "Normalize a raw get_forecast response into a tidy array of daily entries " +
        "(date, weekday, temp min/max/avg, rain mm & probability, wind, UV, sunshine hours, condition text). " +
        "Run this on each get_forecast result before scoring/ranking/filtering. " +
        "Output `days` feeds score_activity_day, best_day, rank_weather, filter_days, compare_forecasts.",
      inputSchema: z.object({
        forecast: z.object({ daily: z.record(z.any()).optional() }).passthrough()
          .describe("The full JSON returned by get_forecast (must contain a `daily` block)."),
        label: z.string().optional()
          .describe("Human label for this location, e.g. 'Moscow'. Carried into the output."),
      }),
    },
    async (params) => {
      const daily = (params.forecast as { daily?: Record<string, unknown> }).daily;
      if (!daily || !Array.isArray((daily as { time?: unknown }).time)) {
        return jsonResult({ error: "No daily data in forecast. Call get_forecast with a `daily` variable list first." });
      }
      const days = normalizeDaily(daily as Parameters<typeof normalizeDaily>[0]);
      return jsonResult({ label: params.label, count: days.length, days });
    }
  );

  // ── describe_weather_code — WMO code(s) → text ───────────────────────────
  server.registerTool(
    "describe_weather_code",
    {
      description:
        "Translate WMO weather code(s) into human-readable descriptions (e.g. 95 → 'Thunderstorm'). " +
        "Accepts a single code or an array.",
      inputSchema: z.object({
        code:

de(s) into human-readable descriptions (e.g. 95 → 'Thunderstorm'). " +
        "Accepts a single code or an array.",
      inputSchema: z.object({
        code: z.number().int().optional().describe("A single WMO weather code."),
        codes: z.array(z.number().int()).optional().describe("Multiple WMO weather codes."),
      }),
    },
    async (params) => {
      if (params.codes) {
        return jsonResult({ descriptions: params.codes.map((c) => ({ code: c, description: wmoDescription(c) })) });
      }
      if (typeof params.code === "number") {
        return jsonResult({ code: params.code, description: wmoDescription(params.code) });
      }
      return jsonResult({ error: "Provide `code` or `codes`." });
    }
  );

  // ── score_activity_day — one day + activity → score + reasons ────────────
  server.registerTool(
    "score_activity_day",
    {
      description:
        "Score a SINGLE normalized day (0–100) for how good it is for an activity, with reasons. " +
        "Use to evaluate one specific day; for picking the best across many days use best_day or rank_weather.",
      inputSchema: z.object({
        day: NDaySchema.describe("One normalized day from summarize_forecast."),
        activity: ActivityEnum,
      }),
    },
    async (params) => {
      const { score, reasons } = scoreActivityDay(params.day, params.activity as Activity);
      return jsonResult({ date: params.day.date, activity: params.activity, score, reasons, summary: summaryLine(params.day as NDay) });
    }
  );

  // ── best_day — best day for ONE location ─────────────────────────────────
  server.registerTool(
    "best_day",
    {
      description:
        "Pick the best day for an activity from ONE location's normalized days. " +
        "Answers 'when this week is best

best_day",
    {
      description:
        "Pick the best day for an activity from ONE location's normalized days. " +
        "Answers 'when this week is best for X in <city>?'. For comparing MULTIPLE cities use rank_weather.",
      inputSchema: z.object({
        label: z.string().optional().describe("Location label, e.g. 'Moscow'."),
        days: z.array(NDaySchema).min(1).describe("Normalized days from summarize_forecast."),
        activity: ActivityEnum,
      }),
    },
    async (params) => {
      const ranked = params.days
        .map((d) => ({ day: d as NDay, ...scoreActivityDay(d, params.activity as Activity) }))
        .sort((a, b) => b.score - a.score);
      const top = ranked[0];
      return jsonResult({
        label: params.label,
        activity: params.activity,
        best: { date: top.day.date, weekday: top.day.weekday, score: top.score, reasons: top.reasons, summary: summaryLine(top.day) },
        ranking: ranked.map((r) => ({ date: r.day.date, weekday: r.day.weekday, score: r.score })),
      });
    }
  );

  // ── rank_weather — best (day, location) across MANY locations ────────────
  server.registerTool(
    "rank_weather",
    {
      description:
        "Compare MULTIPLE locations and find the single best (day + location) for an activity. " +
        "Answers 'which city has the best weather for X this week?'. " +
        "Feed it the summarize_forecast output of each location.",
      inputSchema: z.object({
        locations: z.array(z.object({
          label: z.string().describe("Location label, e.g. 'Sochi'."),
          days: z.array(NDaySchema).min(1),
        })).min(1).describe("Per-location normalized days (one entry per city)."),
        activity: ActivityEnum,
        date: z.string().optional().describe("Restrict to

min(1).describe("Per-location normalized days (one entry per city)."),
        activity: ActivityEnum,
        date: z.string().optional().describe("Restrict to this YYYY-MM-DD; omit to consider the whole range."),
      }),
    },
    async (params) => {
      const scored = params.locations.flatMap((loc) =>
        loc.days
          .filter((d) => !params.date || d.date === params.date)
          .map((d) => ({ location: loc.label, day: d as NDay, ...scoreActivityDay(d, params.activity as Activity) }))
      ).sort((a, b) => b.score - a.score);

      if (scored.length === 0) return jsonResult({ error: "No matching days to rank." });

      const best = scored[0];
      const explanation =
        `Best for ${params.activity}: ${best.day.weekday} ${best.day.date} in ${best.location} — ` +
        `${summaryLine(best.day)}. Score ${best.score} of ${scored.length} day/location combos` +
        (best.reasons.length ? ` (${best.reasons.join(", ")})` : "") + ".";
      return jsonResult({
        activity: params.activity,
        considered: scored.length,
        best: { location: best.location, date: best.day.date, weekday: best.day.weekday, score: best.score, reasons: best.reasons },
        explanation,
        ranking: scored.slice(0, 12).map((r) => ({ location: r.location, date: r.day.date, weekday: r.day.weekday, score: r.score })),
      });
    }
  );

  // ── filter_days — keep days matching constraints ─────────────────────────
  server.registerTool(
    "filter_days",
    {
      description:
        "Keep only the days that satisfy weather constraints (dry-enough, warm-enough, calm-enough…). " +
        "Useful as a pre-filter before scoring, e.g. 'days under 2mm rain and 18–26°C'.",
      inputSchema: z.object({
        days: z.array(NDaySchema).min(1),

"Useful as a pre-filter before scoring, e.g. 'days under 2mm rain and 18–26°C'.",
      inputSchema: z.object({
        days: z.array(NDaySchema).min(1),
        max_precipitation_mm: z.number().optional(),
        max_rain_probability_pct: z.number().optional(),
        min_temp: z.number().optional().describe("Minimum daily average temperature (°C)."),
        max_temp: z.number().optional().describe("Maximum daily average temperature (°C)."),
        max_wind_kmh: z.number().optional(),
        min_sunshine_hours: z.number().optional(),
      }),
    },
    async (params) => {
      const matched = params.days.filter((d) =>
        (params.max_precipitation_mm === undefined || d.precipitation_mm <= params.max_precipitation_mm) &&
        (params.max_rain_probability_pct === undefined || d.rain_probability_pct <= params.max_rain_probability_pct) &&
        (params.min_temp === undefined || d.temp_avg >= params.min_temp) &&
        (params.max_temp === undefined || d.temp_avg <= params.max_temp) &&
        (params.max_wind_kmh === undefined || d.wind_speed_kmh <= params.max_wind_kmh) &&
        (params.min_sunshine_hours === undefined || d.sunshine_hours >= params.min_sunshine_hours)
      );
      return jsonResult({ matched: matched.length, of: params.days.length, days: matched });
    }
  );

  // ── compare_forecasts — side-by-side table by date ───────────────────────
  server.registerTool(
    "compare_forecasts",
    {
      description:
        "Build a side-by-side comparison table of several locations by date " +
        "(temp, rain, wind, sunshine). Pure presentation — no scoring. " +
        "Use when the user wants the raw numbers next to each other rather than a single winner.",
      inputSchema: z.object({
        locations: z.array(z.object({

Use when the user wants the raw numbers next to each other rather than a single winner.",
      inputSchema: z.object({
        locations: z.array(z.object({
          label: z.string(),
          days: z.array(NDaySchema).min(1),
        })).min(2).describe("Two or more locations' normalized days."),
      }),
    },
    async (params) => {
      const dates = [...new Set(params.locations.flatMap((l) => l.days.map((d) => d.date)))].sort();
      const table = dates.map((date) => {
        const row: Record<string, unknown> = { date };
        for (const loc of params.locations) {
          const d = loc.days.find((x) => x.date === date) as NDay | undefined;
          row[loc.label] = d
            ? { temp: `${d.temp_min}–${d.temp_max}°C`, rain_mm: d.precipitation_mm, wind_kmh: d.wind_speed_kmh, sun_h: d.sunshine_hours, weather: d.weather ?? wmoDescription(d.weather_code ?? -1) }
            : null;
        }
        return row;
      });
      return jsonResult({ locations: params.locations.map((l) => l.label), table });
    }
  );

  // ── grid_points — sample coordinates within a radius ─────────────────────
  server.registerTool(
    "grid_points",
    {
      description:
        "Generate sample coordinates within a radius of a center point, each labeled by distance + " +
        "compass direction (e.g. '50 km NE'). Pure geometry — points are positions, not city names. " +
        "Use to answer 'best weather within N km of <place>?': geocode the center → grid_points → " +
        "get_forecast on each point → summarize_forecast → rank_weather.",
      inputSchema: z.object({
        center_latitude: z.number().min(-90).max(90).describe("Center latitude (from geocode)."),
