fn clean_user_text(text: &str) -> String {
    let text = profile::strip_inline_markers(text);
    let mut out = Vec::new();
    for raw in text.lines() {
        let mut line = raw.trim_end().to_string();
        let trimmed = line.trim();
        if trimmed.is_empty() {
            out.push(String::new());
            continue;
        }
        let table_rule = trimmed.chars().all(|c| matches!(c, '|' | '-' | ':' | ' '));
        if table_rule && trimmed.contains('|') {
            continue;
        }
        while line.trim_start().starts_with('#') {
            let without = line.trim_start().trim_start_matches('#').trim_start();
            line = without.to_string();
        }
        line = line.replace("**", "").replace("__", "").replace('`', "");
        if line.contains('|') {
            let parts = line
                .split('|')
                .map(str::trim)
                .filter(|p| !p.is_empty())
                .collect::<Vec<_>>();
            if !parts.is_empty() {
                line = parts.join(" • ");
            }
        }
        out.push(line);
    }

    let mut cleaned = Vec::new();
    let mut blank = false;
    for line in out {
        if line.trim().is_empty() {
            if !blank {
                cleaned.push(line);
            }
            blank = true;
        } else {
            blank = false;
            cleaned.push(line);
        }
    }
    cleaned.join("\n").trim().to_string()
}

