fn spawn_typing(bot: Bot, chat: ChatId) -> tokio::task::JoinHandle<()> {
    tokio::spawn(async move {
        loop {
            let _ = bot
                .send_chat_action(chat, teloxide::types::ChatAction::Typing)
                .await;

wn(async move {
