    let tool = it
        .next()
        .filter(|s| !s.is_empty())
        .ok_or("missing <tool>")?;
    let json = match it.next().map(str::trim).filter(|s| !s.is_empty()) {
        None => None,
        Some(raw) => {
            let val: serde_json::Value =
