                // Turn reqwest's opaque error into something a human can act on.
                let why = if e.is_timeout() {
                    format!(
                        "no response from {} within {LLM_TIMEOUT:?} (provider slow or hung)",
                        self.cfg.base_url
                    )
                } else if e.is_connect() {
